class Solution(object):
    def reverseByType(self, s):
        letters = [c for c in s if c.isalpha()][::-1]
        specials = [c for c in s if not c.isalpha()][::-1]
        li = si = 0
        result = []
        for c in s:
            if c.isalpha():
                result.append(letters[li])
                li += 1
            else:
                result.append(specials[si])
                si += 1
        return ''.join(result)
